features.snippet:
wire result;
input [64:0] inp_p; // 65-bit signal
assign result = &inp_p;

reg state: UInt<1>, clock with: (reset => (arst, 1'b0));
wire x = xorr(inp_bb); // XOR reduction
wire next = state ? 1'b0 : (x ? ~state : state);

struct inner { logic [7:0] o; logic [64:0] p; logic [25:0] ab; }
struct mid { inner f[1][5]; }
input mid d[5];
wire [64:0] val = d[4][0].f.p;

logic [55:0] db; // 56-bit
logic [95:0] result;
assign result = {db[55], db}; // pad 56-bit to 57-bit

reg state: UInt<1>, clock with: (reset => (arst, 1'b0));
wire next_state;
always @(posedge clock or posedge arst)
  if (arst) state <= 1'b0;
  else state <= next_state;
assign next_state = state ? 1'b0 : some_expr;
